#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long a, b, c;
        scanf("%lld %lld %lld", &a, &b, &c);
        long long mn = a;
        if (b < mn) mn = b;
        if (c < mn) mn = c;
        long long ans = a + b + c - mn;
        printf("%lld\n", ans);
    }
    return 0;
}

